class Solution:
    def construct2DArray(self, original, m, n):
        if len(original) != m * n:
            return []
        grid = []
        it = iter(original)
        for _ in range(m):
            row = []
            for _ in range(n):
                row.append(next(it))
            grid.append(row)
        return grid

